-- Seeder data laporan keuangan dari /Users/alfreinsco/Downloads/data dede.xlsx
-- Data transaksi dibuat bervariasi per bulan, namun total produksi, pendapatan, biaya, dan laba tetap mengikuti Excel.
SET @seed_marker = _utf8mb4'[Seeder data dede]' COLLATE utf8mb4_unicode_ci;
SET @id_pelanggan_laporan = 2;
VALUES (@id_pelanggan_laporan, 'Pelanggan Laporan Keuangan', '-', 'Data seeder laporan keuangan 2023-2025')
ON DUPLICATE KEY UPDATE nama_pelanggan = VALUES(nama_pelanggan), nomor_telepon = VALUES(nomor_telepon), alamat = VALUES(alamat);
SET @id_produk_1kg = (SELECT id_produk FROM produk WHERE nama_produk = 'Minyak Kayu Putih 1Kg' LIMIT 1);
DELETE FROM penjualan WHERE id_pelanggan = @id_pelanggan_laporan AND tanggal_transaksi BETWEEN '2023-01-01' AND '2025-12-31';
DELETE FROM pengeluaran WHERE keterangan LIKE CONCAT(@seed_marker, '%');

